var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아, 여기 있었군, 유미나.","JPN":"ああ、ここにいたのか、ミナ。","ENG":"Oh, there you are, Yoo Mina.","TWN":"喔，原來你在這裡，劉米娜。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기다리고 있었어, 를르슈","JPN":"待ってたよ、ルルーシュ。","ENG":"I've been waiting for you, Lelouch.","TWN":"我在等你，魯路修。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"흠, 표정을 보아하니, 아무래도 기억이 돌아왔나 보군.","JPN":"ふむ。その顔つき、どうやら記憶を取り戻したようだな。","ENG":"Hmm, from the looks of it, you've got your memories back?","TWN":"哼，看你的表情，應該是想起所有的事了吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 곧 <color=#ffd34c>전야제 </color>가 끝이 날 거야. 이번에는 시간이 별로 없어.","JPN":"しかし、まもなく今日が、<color=#ffd34c>学園祭の前日</color>が終わる。今回はもう時間がない。","ENG":"The <color=#ffd34c>festival preparation</color> is going to end soon. We don't have a lot of time right now.","TWN":"但<color=#ffd34c>這一天</color>就快結束了，這次沒剩多少時間了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이번에는? 역시 너는 뭔가 알고 있구나.","JPN":"今回は？　やっぱりあなたは何か知っているようだね。","ENG":"Don't have time? So you do know something.","TWN":"這次？你果然知道什麼！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면 가르쳐 줘, 를르슈.","JPN":"なら教えて、ルルーシュ。","ENG":"Then tell me, Lelouch.","TWN":"告訴我，魯路修。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴 도대체 어디야? 여기는 카운터 아카데미가 아니잖아. 그리고 너희들은 또 누구고?","JPN":"ここはいったいどこなの？　ここはカウンターアカデミーじゃないよね？　そして、あなたたちは何者？","ENG":"Where am I? I know this isn't the Counter Academy. And who are you guys?","TWN":"這裡到底是哪裡？這裡並不是制裁者學院，你們又是誰？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 우리들은 매일 같이 학원제를 준비하고 있는 거지?","JPN":"どうして、私たちは毎日学園祭の準備を繰り返してるの?","ENG":"Why are we preparing for the festival every day?","TWN":"為什麼我們會每天一起預備學園祭？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 나이엘을 조심하라는 건 또 무슨 소리야? 나이엘이 어때서 그러는 거야?","JPN":"それにナイエルに注意しろっていうのは、どういう意味？　ナイエルがどうしたというの？","ENG":"What did you mean by \\"be careful of Naielle?\\" What's she got to do with this?","TWN":"還有，你叫我要小心奈爾，那又是什麼意思？奈爾有什麼問題嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"한 번에 질문이 너무 많군. 미안하지만 전부 대답하기에는 시간이 없어.","JPN":"一度に質問が多すぎるな。悪いが、全て答えるには時間がない。","ENG":"You're asking too many questions at once. I'm sorry, but I have no time to answer them all.","TWN":"你一下子問這麼多問題，很抱歉，我沒時間全部回答你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이전 루프에서 확인해본 결과, 너와 단 둘이 접촉할 수 있는 시간은 고작 3분정도니까.","JPN":"前のループで確かめた結果、お前と二人きりで接触できる時間はたったの3分程度だ。","ENG":"From the previous loop, I've confirmed that we have only 3 minutes to talk to each other in private.","TWN":"按照之前的經驗，我可以和你單獨相處的時間只有三分鐘左右。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이전 루프라고? 나이엘이 음료수를 쏟았을 때를 이야기하는 거야?","JPN":"前のループ？　ナイエルにジュースがかかった時のこと？","ENG":"Previous loop? You mean when Naielle showered herself with soda?","TWN":"之前的經驗？你是指奈爾把飲料灑出來的時候嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래, 곧 여기에 그 나이엘이 들이닥칠 거다.","JPN":"そうだ。そのナイエルが間もなくここに来る。","ENG":"Correct. She will be here any second now.","TWN":"沒錯，奈爾等一下就會進來這裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"녀석이 조금이라도 위화감을 느끼면 곧바로 전야제는 리셋되고 처음부터 학원제를 준비하게 되지.","JPN":"あいつが少しでも違和感を覚えると、すぐに<color=#ffd34c>学園祭の前日</color>はリセットされて最初からやり直すことになる。","ENG":"As soon as she feels a little discomfort, the day resets and preparations for the festival start all over again.","TWN":"只要她稍微感覺到一點違和感，就會立刻重演這一天，又要重頭開始預備學園祭。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 리셋이라고? 또 기억을 잃게 된다는 거야?","JPN":"ま、待って！　リセット！？　また記憶を失ってしまうってこと？","ENG":"W-wait! Reset? I'm gonna lose my memories again?","TWN":"等等！你說重演？意思是我又會失去記憶嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 이제 시간이 별로 없어.","JPN":"ミナ、あまり時間がない。","ENG":"Mina, we're running out of time.","TWN":"米娜，沒時間了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이 학원제를 끝내 버리기 위해서는 너의 힘이 필요해.","JPN":"俺たちがこの<color=#ffd34c>学園祭の前日</color>から抜け出すためには、お前の力が必要なんだ。","ENG":"I need your help to end this festival.","TWN":"要結束這場學園祭，就需要你的力量。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"반드시 기억해내는 거야, 유미나. 눈을 뜨자마자…… 킹의 발 밑을 확인해.","JPN":"必ず思い出すんだ、ヤナギ・ミナ。目を覚ましたらすぐに……キングの足下を確認しろ。","ENG":"You have to keep remembering, Yoo Mina. As soon as you open your eyes... check under the king.","TWN":"劉米娜，你一定要想起來。你一睜開眼睛…… 就確認國王的腳底。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"킹의 발 밑? 그건 도대체 무슨…….","JPN":"キングの足下？　それはいったいどういう……","ENG":"Under the king? That makes no sense...","TWN":"國王的腳底？那什麼意思……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"야! 너희들! 여기서 뭘 하는 거야!?","JPN":"あーっ！　あんたたち、こんなところにいたのね！","ENG":"Hey! You two! What are you doing here?!","TWN":"喂！你們二個！在這裡做什麼！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};